    40→  /**
    41→   * Initialize the Anthropic client (supports API key or OAuth token)
    42→   */
    43→  private static async getClient(): Promise<Anthropic> {
    44→    if (this.client) {
    45→      return this.client;
    46→    }
    47→
    48→    const creds = await AuthenticationService.getAnthropicCredentials();
    49→    if (!creds) {
    50→      throw new Error('Anthropic not configured. Run: claude setup-token');
    51→    }
    52→
    53→    if (creds.authToken) {
    54→      this.client = new Anthropic({
    55→        authToken: creds.authToken,
    56→        defaultHeaders: { 'anthropic-beta': 'oauth-2025-04-20' },
    57→        defaultQuery: { beta: 'true' },
    58→      });
    59→    } else if (creds.apiKey) {
    60→      this.client = new Anthropic({ apiKey: creds.apiKey });
    61→    } else {
    62→      throw new Error('No valid Anthropic credentials found');
    63→    }
    64→
    65→    return this.client;
    66→  }
