     4→/**
     5→ * Authentication service that manages token refresh and validation
     6→ */
     7→export class AuthenticationService {
     8→  private static readonly TOKEN_REFRESH_BUFFER = 5 * 60 * 1000; // 5 minutes
     9→
    10→  /**
    11→   * Get valid Google access token (auto-refreshes if needed)
    12→   */
    13→  static async getGoogleAccessToken(): Promise<string | null> {
    14→    const credentials = await CredentialManager.getCredentials('google');
    15→    if (!credentials) {
    16→      return null;
    17→    }
    18→
    19→    // Check if token is expired or about to expire
    20→    const now = Date.now();
    21→    const expiryDate = credentials.expiry_date || 0;
    22→
    23→    if (expiryDate - now > this.TOKEN_REFRESH_BUFFER) {
    24→      // Token is still valid
    25→      return credentials.access_token;
    26→    }
    27→
    28→    // Token expired or about to expire, refresh it
    29→    if (!credentials.refresh_token) {
    30→      throw new Error('No refresh token available');
    31→    }
    32→
