     6→// Credential schemas
     7→const GoogleCredentialsSchema = z.object({
     8→  access_token: z.string(),
     9→  refresh_token: z.string(),
    10→  token_type: z.string(),
    11→  expiry_date: z.number(),
    12→  scope: z.string(),
    13→});
    14→
    15→const NotionCredentialsSchema = z.object({
    16→  access_token: z.string(),
    17→  bot_id: z.string().optional(),
    18→  workspace_id: z.string().optional(),
    19→  workspace_name: z.string().optional(),
    20→});
    21→
    22→const AnthropicCredentialsSchema = z.object({
    23→  api_key: z.string().optional(),
    24→  auth_token: z.string().optional(),
    25→});
    26→
    27→const CredentialsSchema = z.object({
    28→  google: GoogleCredentialsSchema.optional(),
    29→  notion: NotionCredentialsSchema.optional(),
    30→  anthropic: AnthropicCredentialsSchema.optional(),
    31→});
    32→
    33→export type GoogleCredentials = z.infer<typeof GoogleCredentialsSchema>;
    34→export type NotionCredentials = z.infer<typeof NotionCredentialsSchema>;
    35→export type AnthropicCredentials = z.infer<typeof AnthropicCredentialsSchema>;
    36→export type Credentials = z.infer<typeof CredentialsSchema>;
    37→export type ServiceName = keyof Credentials;
    38→
    39→/**
    40→ * Manages credential storage with multi-tier discovery
    41→ */
    42→export class CredentialManager {
    43→  private static credentialsPath: string;
    44→  private static credentials: Credentials | null = null;
    45→
    46→  static async initialize(): Promise<void> {
    47→    const configDir = ConfigManager.getConfigDir();
    48→    await fs.ensureDir(configDir);
    49→    this.credentialsPath = path.join(configDir, 'credentials.json');
    50→  }
    51→
    52→  /**
    53→   * Get credentials for a specific service with multi-tier discovery
    54→   * 1. Credentials file
    55→   * 2. Environment variables
    56→   */
    57→  static async getCredentials<T extends ServiceName>(
    58→    service: T
    59→  ): Promise<Credentials[T] | null> {
    60→    // Tier 1: Check encrypted file
    61→    const fileCredentials = await this.loadFromFile();
    62→    if (fileCredentials && fileCredentials[service]) {
    63→      return fileCredentials[service] as Credentials[T];
    64→    }
    65→
    66→    // Tier 2: Check environment variables
    67→    const envCredentials = this.loadFromEnvironment(service);
    68→    if (envCredentials) {
    69→      return envCredentials as Credentials[T];
    70→    }
    71→
    72→    return null;
    73→  }
    74→
    75→  /**
    76→   * Save credentials for a specific service
    77→   */
    78→  static async saveCredentials<T extends ServiceName>(
    79→    service: T,
    80→    credentials: Credentials[T]
    81→  ): Promise<void> {
    82→    await this.initialize();
    83→
    84→    const current = await this.loadFromFile();
    85→    const updated: Credentials = {
    86→      ...current,
    87→      [service]: credentials,
    88→    };
    89→
    90→    const json = JSON.stringify(updated, null, 2);
    91→    await fs.writeFile(this.credentialsPath, json, { mode: 0o600 });
    92→    this.credentials = updated;
    93→  }
    94→
    95→  /**
    96→   * Delete credentials for a specific service
    97→   */
    98→  static async deleteCredentials(service: ServiceName): Promise<void> {
    99→    const current = await this.loadFromFile();
   100→    if (current) {
   101→      delete current[service];
   102→      const json = JSON.stringify(current, null, 2);
   103→      await fs.writeFile(this.credentialsPath, json, { mode: 0o600 });
   104→      this.credentials = current;
   105→    }
   106→  }
   107→
   108→  /**
   109→   * Check if credentials exist for a service
   110→   */
   111→  static async hasCredentials(service: ServiceName): Promise<boolean> {
   112→    const creds = await this.getCredentials(service);
   113→    return creds !== null;
   114→  }
   115→
   116→  /**
   117→   * Load all credentials from file
   118→   */
   119→  private static async loadFromFile(): Promise<Credentials> {
   120→    if (this.credentials) {
   121→      return this.credentials;
   122→    }
   123→
   124→    await this.initialize();
   125→
   126→    if (!(await fs.pathExists(this.credentialsPath))) {
   127→      return {};
   128→    }
   129→
   130→    try {
   131→      const raw = await fs.readFile(this.credentialsPath, 'utf8');
   132→      const parsed = JSON.parse(raw);
   133→      this.credentials = CredentialsSchema.parse(parsed);
   134→      return this.credentials;
   135→    } catch (error) {
   136→      console.error('Failed to load credentials:', error);
   137→      return {};
   138→    }
   139→  }
   140→
   141→  /**
   142→   * Load credentials from environment variables
   143→   */
   144→  private static loadFromEnvironment(service: ServiceName): any {
   145→    switch (service) {
   146→      case 'google':
   147→        if (process.env.GOOGLE_CREDENTIALS) {
   148→          try {
   149→            return JSON.parse(process.env.GOOGLE_CREDENTIALS);
   150→          } catch {
   151→            return null;
   152→          }
   153→        }
   154→        break;
   155→
   156→      case 'notion':
   157→        if (process.env.NOTION_TOKEN) {
   158→          return { access_token: process.env.NOTION_TOKEN };
   159→        }
   160→        break;
   161→
   162→      case 'anthropic':
   163→        if (process.env.ANTHROPIC_API_KEY) {
   164→          return { api_key: process.env.ANTHROPIC_API_KEY };
   165→        }
   166→        if (process.env.ANTHROPIC_AUTH_TOKEN) {
   167→          return { auth_token: process.env.ANTHROPIC_AUTH_TOKEN };
   168→        }
   169→        break;
   170→    }
   171→    return null;
   172→  }
   173→
   174→  /**
   175→   * Get the credentials file path
   176→   */
   177→  static getCredentialsPath(): string {
   178→    return this.credentialsPath || path.join(ConfigManager.getConfigDir(), 'credentials.json');
   179→  }
   180→}
