     7→/**
     8→ * OAuth 2.0 Configuration
     9→ */
    10→export interface OAuthConfig {
    11→  clientId: string;
    12→  clientSecret?: string;
    13→  authorizationUrl: string;
    14→  tokenUrl: string;
    15→  redirectUri: string;
    16→  scopes: string[];
    17→  usePKCE?: boolean;
    18→}
    19→
    20→/**
    21→ * OAuth 2.0 Token Response
    22→ */
    23→export interface OAuthTokens {
    24→  access_token: string;
    25→  refresh_token?: string;
    26→  token_type: string;
    27→  expires_in?: number;
    28→  scope?: string;
    29→  expiry_date?: number;
    30→}
    31→
    32→/**
    33→ * Generate PKCE challenge
    34→ */
    35→function generatePKCE(): { verifier: string; challenge: string } {
    36→  const verifier = crypto.randomBytes(32).toString('base64url');
    37→  const challenge = crypto.createHash('sha256').update(verifier).digest('base64url');
    38→  return { verifier, challenge };
    39→}
    40→
    41→/**
    42→ * Start OAuth 2.0 flow with PKCE
    43→ */
    44→export async function startOAuthFlow(config: OAuthConfig): Promise<OAuthTokens> {
    45→  const state = crypto.randomBytes(16).toString('hex');
    46→  let pkce: { verifier: string; challenge: string } | undefined;
    47→
    48→  if (config.usePKCE) {
    49→    pkce = generatePKCE();
    50→  }
    51→
    52→  // Build authorization URL
    53→  const authUrl = new URL(config.authorizationUrl);
    54→  authUrl.searchParams.set('client_id', config.clientId);
    55→  authUrl.searchParams.set('redirect_uri', config.redirectUri);
    56→  authUrl.searchParams.set('response_type', 'code');
    57→  authUrl.searchParams.set('scope', config.scopes.join(' '));
    58→  authUrl.searchParams.set('state', state);
    59→  authUrl.searchParams.set('access_type', 'offline');
    60→  authUrl.searchParams.set('prompt', 'consent');
    61→
    62→  if (pkce) {
    63→    authUrl.searchParams.set('code_challenge', pkce.challenge);
    64→    authUrl.searchParams.set('code_challenge_method', 'S256');
    65→  }
    66→
    67→  console.log(chalk.cyan('\n🔐 Opening browser for authentication...'));
    68→  console.log(chalk.gray('If browser doesn\'t open, visit:'));
    69→  console.log(chalk.blue(authUrl.toString()));
    70→  console.log();
    71→
    72→  // Open browser
    73→  await open(authUrl.toString());
    74→
    75→  // Start local callback server
    76→  return new Promise((resolve, reject) => {
    77→    const server = createServer(async (req: IncomingMessage, res: ServerResponse) => {
    78→      if (!req.url) {
    79→        res.writeHead(400);
    80→        res.end('Bad Request');
    81→        return;
    82→      }
    83→
    84→      const url = new URL(req.url, config.redirectUri);
    85→      const code = url.searchParams.get('code');
    86→      const returnedState = url.searchParams.get('state');
    87→      const error = url.searchParams.get('error');
    88→
    89→      if (error) {
    90→        res.writeHead(200, { 'Content-Type': 'text/html' });
    91→        res.end(`
    92→          <html>
    93→            <body style="font-family: system-ui; padding: 2rem; text-align: center;">
    94→              <h1>❌ Authentication Failed</h1>
    95→              <p>Error: ${error}</p>
    96→              <p>You can close this window.</p>
    97→            </body>
    98→          </html>
    99→        `);
   100→        server.close();
   101→        reject(new Error(`OAuth error: ${error}`));
   102→        return;
   103→      }
   104→
   105→      if (!code || returnedState !== state) {
   106→        res.writeHead(400);
   107→        res.end('Invalid request');
   108→        server.close();
   109→        reject(new Error('Invalid OAuth callback'));
   110→        return;
   111→      }
   112→
   113→      // Exchange code for tokens
   114→      try {
   115→        const tokenParams: any = {
   116→          code,
   117→          client_id: config.clientId,
   118→          redirect_uri: config.redirectUri,
   119→          grant_type: 'authorization_code',
   120→        };
   121→
   122→        if (config.clientSecret) {
   123→          tokenParams.client_secret = config.clientSecret;
   124→        }
   125→
   126→        if (pkce) {
   127→          tokenParams.code_verifier = pkce.verifier;
   128→        }
   129→
   130→        const tokenResponse = await fetch(config.tokenUrl, {
   131→          method: 'POST',
   132→          headers: {
   133→            'Content-Type': 'application/x-www-form-urlencoded',
   134→          },
   135→          body: new URLSearchParams(tokenParams).toString(),
   136→        });
   137→
   138→        if (!tokenResponse.ok) {
   139→          const errorText = await tokenResponse.text();
   140→          throw new Error(`Token exchange failed: ${errorText}`);
   141→        }
   142→
   143→        const tokens = await tokenResponse.json();
   144→
   145→        // Calculate expiry date
   146→        if (tokens.expires_in) {
   147→          tokens.expiry_date = Date.now() + tokens.expires_in * 1000;
   148→        }
   149→
   150→        res.writeHead(200, { 'Content-Type': 'text/html' });
   151→        res.end(`
   152→          <html>
   153→            <body style="font-family: system-ui; padding: 2rem; text-align: center;">
   154→              <h1>✅ Authentication Successful!</h1>
   155→              <p>You can close this window and return to the terminal.</p>
   156→              <script>setTimeout(() => window.close(), 2000);</script>
   157→            </body>
   158→          </html>
   159→        `);
   160→
   161→        server.close();
   162→        resolve(tokens);
   163→      } catch (error) {
   164→        res.writeHead(500);
   165→        res.end('Token exchange failed');
   166→        server.close();
   167→        reject(error);
   168→      }
   169→    });
   170→
   171→    // Extract port from redirect URI
   172→    const redirectUrl = new URL(config.redirectUri);
   173→    const port = parseInt(redirectUrl.port) || 8765;
   174→
   175→    server.listen(port, () => {
   176→      console.log(chalk.gray(`Waiting for callback on ${config.redirectUri}...`));
   177→    });
   178→
   179→    // Timeout after 5 minutes
   180→    setTimeout(() => {
   181→      server.close();
   182→      reject(new Error('OAuth flow timed out'));
   183→    }, 5 * 60 * 1000);
   184→  });
   185→}
