    76→    socket.on("tool_result", (data: { type: string; query: string; items: ProductItem[] }) => {
    77→      if (data.type === "clothing_results" && data.items?.length > 0) {
    78→        setProducts((prev) => [
    79→          ...prev,
    80→          { id: `product-${Date.now()}`, query: data.query, items: data.items },
    81→        ]);
    82→      }
    83→    });
    84→
    85→    socket.on("session_ended", (data: { summary: string; stats: { items_shown: number; likes: number; dislikes: number } }) => {
    86→      setSessionActive(false);
    87→      miraBufferRef.current = "";
    88→      setMessages((prev) => [
    89→        ...prev,
    90→        {
    91→          id: `sys-${Date.now()}`,
    92→          role: "system",
    93→          text: `Session ended. ${data.summary || ""} (Items shown: ${data.stats.items_shown}, Likes: ${data.stats.likes}, Dislikes: ${data.stats.dislikes})`,
    94→        },
    95→      ]);
    96→    });
    97→
    98→    socket.on("session_recap", (data: { summary?: string; liked_items?: string[] }) => {
    99→      const parts: string[] = [];
   100→      if (data.summary) parts.push(data.summary);
   101→      if (data.liked_items?.length) parts.push(`Liked items: ${data.liked_items.join(", ")}`);
   102→      if (parts.length > 0) {
   103→        setMessages((prev) => [
   104→          ...prev,
   105→          { id: `recap-${Date.now()}`, role: "system", text: `Recap: ${parts.join(" | ")}` },
   106→        ]);
   107→      }
