     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import { useCamera } from "@/hooks/useCamera";
     6→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     7→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
     8→import { socket } from "@/lib/socket";
     9→import type { DetectedGesture, GestureType } from "@/types/gestures";
    10→
    11→export default function MirrorPage() {
    12→  const searchParams = useSearchParams();
    13→  const userId = searchParams.get("user_id");
    14→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    15→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    16→  const gestureKeyRef = useRef(0);
    17→  const [gestureKey, setGestureKey] = useState(0);
    18→
    19→  // Connect socket and join user room
    20→  useEffect(() => {
    21→    socket.connect();
    22→
    23→    if (userId) {
    24→      socket.emit("join_room", { user_id: userId });
    25→    }
    26→
    27→    return () => {
    28→      socket.disconnect();
    29→    };
    30→  }, [userId]);
    31→
    32→  // Listen for snapshot requests from the backend
    33→  useEffect(() => {
    34→    const handleSnapshotRequest = () => {
    35→      const video = videoRef.current;
    36→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
    37→
    38→      const canvas = document.createElement("canvas");
    39→      canvas.width = video.videoWidth;
    40→      canvas.height = video.videoHeight;
    41→      const ctx = canvas.getContext("2d");
    42→      if (!ctx) return;
    43→
    44→      ctx.drawImage(video, 0, 0);
    45→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
    46→      // Strip the data URL prefix to get raw base64
    47→      const base64 = dataUrl.split(",")[1];
    48→
    49→      socket.emit("mirror_event", {
    50→        type: "snapshot",
    51→        image_base64: base64,
    52→        user_id: userId,
    53→      });
    54→    };
    55→
    56→    socket.on("request_snapshot", handleSnapshotRequest);
    57→    return () => {
    58→      socket.off("request_snapshot", handleSnapshotRequest);
    59→    };
    60→  }, [videoRef, userId]);
    61→
    62→  const handleGesture = useCallback((gesture: DetectedGesture) => {
    63→    console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
    64→
    65→    setLastGesture(gesture.type);
    66→    gestureKeyRef.current += 1;
    67→    setGestureKey(gestureKeyRef.current);
    68→
    69→    socket.emit("gesture_detected", {
    70→      type: gesture.type,
    71→      confidence: gesture.confidence,
    72→      timestamp: gesture.timestamp,
    73→    });
    74→  }, []);
    75→
    76→  const { isLoading: isModelLoading, error: modelError } =
    77→    useGestureRecognizer({
    78→      videoRef,
    79→      isVideoReady: isCameraReady,
    80→      onGesture: handleGesture,
    81→    });
    82→
    83→  return (
    84→    <main
    85→      style={{
    86→        position: "relative",
    87→        width: "100vw",
    88→        height: "100vh",
    89→        background: "#000",
    90→        overflow: "hidden",
    91→      }}
    92→    >
    93→      {/* Webcam feed (mirrored) */}
    94→      <video
    95→        ref={videoRef}
    96→        autoPlay
    97→        playsInline
    98→        muted
    99→        style={{
   100→          position: "absolute",
   101→          top: 0,
   102→          left: 0,
   103→          width: "100%",
   104→          height: "100%",
   105→          objectFit: "cover",
   106→          transform: "scaleX(-1)",
   107→        }}
   108→      />
   109→
   110→      {/* Gesture visual feedback */}
   111→      <GestureIndicator key={gestureKey} gesture={lastGesture} />
   112→
   113→      {/* Status indicators */}
   114→      {(cameraError || modelError) && (
   115→        <div
   116→          style={{
   117→            position: "absolute",
   118→            bottom: 20,
   119→            left: 20,
   120→            color: "#f44",
   121→            fontSize: "1rem",
   122→            zIndex: 30,
   123→          }}
   124→        >
   125→          {cameraError && <div>Camera: {cameraError}</div>}
   126→          {modelError && <div>Model: {modelError}</div>}
   127→        </div>
   128→      )}
   129→
   130→      {isModelLoading && (
   131→        <div
   132→          style={{
   133→            position: "absolute",
   134→            top: "50%",
   135→            left: "50%",
   136→            transform: "translate(-50%, -50%)",
   137→            color: "#fff",
   138→            fontSize: "1.5rem",
   139→            zIndex: 30,
   140→          }}
   141→        >
   142→          Loading gesture recognition...
   143→        </div>
   144→      )}
   145→    </main>
   146→  );
   147→}
