     4→import { googleLogin, UserProfile } from "@/lib/api";
     5→
     6→declare global {
     7→  interface Window {
     8→    google?: {
     9→      accounts: {
    10→        oauth2: {
    11→          initCodeClient: (config: {
    12→            client_id: string;
    13→            scope: string;
    14→            ux_mode: string;
    15→            callback: (response: { code: string }) => void;
    16→          }) => { requestCode: () => void };
    17→        };
    18→      };
    19→    };
    20→  }
    21→}
    22→
    23→interface GoogleSignInProps {
    24→  onSuccess: (user: UserProfile) => void;
    25→  onError: (error: string) => void;
    26→}
    27→
    28→export default function GoogleSignIn({ onSuccess, onError }: GoogleSignInProps) {
    29→  const clientRef = useRef<{ requestCode: () => void } | null>(null);
    30→  const loadingRef = useRef(false);
    31→
    32→  const handleAuth = useCallback(
